#!/usr/bin/python# -*- coding: utf-8 -*-from agent import *from models.products import *X_URLS = ['https://www.tech-critter.com/unboxing-review-bitfenix-comrade/']OLD_URLS = ["https://www.tech-critter.com/roccat-kone-pure-gaming-mouse/", "https://www.tech-critter.com/gamdias-hermes-mechanical-gaming/"]def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request("https://www.tech-critter.com/category/reviews-unboxings/"), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath("//div[@class='elementor-post__text'][h3[@class='elementor-post__title']]")    for rev in revs:        title = rev.xpath("h3//a/text()").string()        url = rev.xpath("h3//a/@href").string()        date = rev.xpath(".//span[contains(@class, 'date')]/text()").string()        if url not in X_URLS:            session.queue(Request(url), process_review, dict(title=title, url=url, date=date))    next_url = data.xpath("//link[@rel='next']/@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict())def process_review(data, context, session):    product = Product()    product.name = context['title'].split('Quick Overview on the ')[-1].split('Unboxing & Review: ')[-1].split('Review – be quiet! ')[-1].split(' Hands-On Review')[0].split('Quick Review: ')[-1].split('Unboxing & Preview – ')[-1].split('First Look – ')[-1].split('First Impression – ')[-1].split('Hands On – ')[-1].split('First Look: ')[-1].split("Review – ")[-1].split(' Review:')[0].split('Overview – ')[-1].split(' Overview')[0].split('Buy: ')[-1].split('eview: ')[-1].split(' – ')[0].split(' Review')[0].split(': ')[0]    product.ssid = context['url'].split("/")[-2]    product.url = data.xpath('//h2[contains(., "Where To Buy")]/following-sibling::ul/li/a/@href').string()    if not product.url:        product.url = data.xpath('//h2[contains(., "Where to buy")]/following-sibling::ul/li/a/@href').string()    if not product.url:        product.url = context['url']    product.category = data.xpath('//meta[@property="article:section"]/@content').string()    if not product.category or product.category == 'Reviews & Unboxings':        product.category = 'Tech'    review = Review()    review.type = 'pro'    review.url = context['url']    review.ssid = product.ssid    review.title = context['title']    review.date = context['date']    author = data.xpath("//h4[contains(@class, 'author-box')]/text()").string()    if author:        review.authors.append(Person(name=author, ssid=author))    grade_list = {'Gold': 3, 'Silver': 2, 'Bronze': 1}    grade_text = data.xpath("//img[regexp:test(@src, 'Bronze|Silver|Gold')]/@data-image-title").string()    if grade_text and grade_text.split('Critter ')[-1] in grade_list:        grade_overall = grade_list[grade_text.split('Critter ')[-1]]        review.grades.append(Grade(type='overall', value=float(grade_overall), best=3.0))    pros = data.xpath('//node()[regexp:test(name(),"h\d")][regexp:test(descendant::text(),"(Pros)")]/following::ul[1]/li')    if not pros:        pros = data.xpath("//p/b[contains(., 'Pros')]/parent::p/following::ul[1]/li")    if not pros:        pros = data.xpath("//b[contains(., 'Pros')]/following::ul[1]/li")    if not pros:        pros = data.xpath("//strong[contains(., 'Pros')]/following::ul[1]/li")    if not pros:        pros = data.xpath("//p[contains(., 'Pros')]/following::ul[1]/li")    if pros:        for pro in pros:            pro = pro.xpath('.//text()').string()            if pro:                review.add_property(type='pros', value=pro)    cons = data.xpath('//node()[regexp:test(name(),"h\d")][regexp:test(descendant::text(),"(Cons )")]/following::ul[1]/li')    if not cons:        cons = data.xpath("//p/b[contains(., 'Cons')]/parent::p/following::ul[1]/li")    if not cons:        cons = data.xpath("//b[contains(., 'Cons')]/following::ul[1]/li")    if not cons:        cons = data.xpath("//strong[contains(., 'Cons')]/following::ul[1]/li")    if not cons:        cons = data.xpath("//p[contains(., 'Cons')]/following::ul[1]/li")    if cons:        for con in cons:            con = con.xpath('.//text()').string()            if con:                review.add_property(type='cons', value=con)    conclusion = ""    conclusion_content = data.xpath('//node()[regexp:test(name(),"h\d")][regexp:test(descendant::text(),"(Verdict|Final Words|Conclusion|Final Thoughts|Wrapping up|Should you buy)")]/following-sibling::*')    for content in conclusion_content:        if content.xpath('text()'):            if not content.xpath('text()/parent::p') and review.url != 'https://www.tech-critter.com/unboxing-review-armaggeddon-kai-9/' or 'Where to buy' in content.xpath('text()').string() or 'As for the question' in content.xpath('text()').string():                break            conclusion += content.xpath('.//text()').string(multiple=True) + " "    if review.url in OLD_URLS:        conclusion = data.xpath('//h2[contains(., "Final Thoughts")]/following-sibling::p//text()').string(multiple=True).split('Cons')[-1]        text_for_split = data.xpath('//h2[contains(., "Final Thoughts")]/following-sibling::p//text()').string(multiple=True).split('Cons')[0]    if conclusion and conclusion != '':        conclusion = conclusion.split("Pros")[0].strip()        review.add_property(type='conclusion', value=conclusion)    excerpt = data.xpath("//div[@class='elementor-widget-container']/p//text()").string(multiple=True)    if excerpt and conclusion:        excerpt = excerpt.split(conclusion)[0]        if review.url in OLD_URLS:            excerpt = excerpt.split(text_for_split)[0]        review.add_property(type='excerpt', value=excerpt)        product.reviews.append(review)        session.emit(product)